script.code:
def main(analysis, trigger):
    from datetime import datetime, timedelta
    now = datetime.utcnow()
    deadlines = []
    regulations = analysis.get('regulations', [])
    if 'GDPR' in regulations:
        deadlines.append({'regulation': 'GDPR', 'authority': 'Supervisory Authority', 'deadline_hours': 72, 'due': (now + timedelta(hours=72)).isoformat()})
    if 'HIPAA' in regulations:
        deadlines.append({'regulation': 'HIPAA', 'authority': 'HHS OCR', 'deadline_hours': 1440, 'due': (now + timedelta(hours=1440)).isoformat()})
    if 'CCPA' in regulations:
        deadlines.append({'regulation': 'CCPA', 'authority': 'California AG', 'deadline_hours': 720, 'due': (now + timedelta(hours=720)).isoformat()})
    deadlines.append({'regulation': 'Individual Notice', 'authority': 'Affected Individuals', 'deadline_hours': 720, 'due': (now + timedelta(hours=720)).isoformat()})
    return {'deadlines': deadlines, 'earliest_deadline': min(d['deadline_hours'] for d in deadlines) if deadlines else 720}

